// Extract polished response from AI Agent output or bypass
// Handles two paths:
// 1. Normal: Build Polisher Context -> Polisher AI Agent -> here
// 2. Bypass: Bypass Polisher -> here (jailbreak, _jailbreak_detected=true)
const agentOutput = $input.item.json;

let ctx;
try {
  ctx = $('Build Polisher Context').item.json;
} catch (e) {
  // Bypass path — Build Polisher Context was not executed
  ctx = agentOutput;
}

const polishedText = agentOutput.polished_response || agentOutput.output || agentOutput.text || ctx.output || '';

return [{ json: {
  ...ctx,
  polished_response: polishedText,
  output: polishedText,
  source_channel: ctx.source_channel,
  model_tier: ctx.model_tier,
  person_id: ctx.person_id,
  session_id: ctx.session_id,
  conversation_privacy: ctx.conversation_privacy,
  _start_ts: ctx._start_ts,
  person_name: ctx.person_name,
  intermediateSteps: ctx.intermediateSteps,
  _jailbreak_detected: ctx._jailbreak_detected || false
} }];

// Platform Formatter
// IMPORTANT: Read from Set Polished Response, NOT $input — SQL Write-Back wipes all item JSON
const ctx = $('Set Polished Response').item.json;
const text = ctx.polished_response || ctx.output || ctx.raw_response || ctx.text;
const platform = ctx.source_channel;

function toTelegramHtml(md) {
  const parts = [];

  // Extract fenced code blocks — escape HTML entities inside them
  md = md.replace(/```(\w+)?\n?([\s\S]*?)```/g, (match, lang, code) => {
    const esc = code.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    parts.push('<pre><code>' + esc + '</code></pre>');
    return '\x00' + (parts.length - 1) + '\x00';
  });

  // Extract inline code — escape HTML entities inside them
  md = md.replace(/`([^`]+)`/g, (match, code) => {
    const esc = code.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    parts.push('<code>' + esc + '</code>');
    return '\x00' + (parts.length - 1) + '\x00';
  });

  // Escape HTML entities in remaining plain text
  md = md.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  // Apply bold and italic on plain text
  md = md.replace(/\*\*([^*]+)\*\*/g, '<b>$1</b>');
  md = md.replace(/(?<!\*)\*([^*]+)\*(?!\*)/g, '<i>$1</i>');

  // Restore code blocks
  md = md.replace(/\x00(\d+)\x00/g, (match, idx) => parts[parseInt(idx)]);

  return md;
}

let formatted;
let parseMode;

if (platform === 'telegram') {
  formatted = toTelegramHtml(text);
  parseMode = 'HTML';
} else {
  formatted = text;
  parseMode = undefined;
}

// Spread ctx (not $input) to preserve source_channel, channel_id, etc.
return [{ json: { ...ctx, formatted_response: formatted, parse_mode: parseMode } }];

// Message Splitter
// Splits long responses at natural boundaries before sending.
// Discord limit: 2000 chars. Telegram limit: 4096 chars.
// Split priority: paragraph break > single newline > sentence end > hard cut.

const text = $input.item.json.formatted_response || '';
const platform = $input.item.json.source_channel;
const limit = platform === 'discord' ? 2000 : 4096;

function splitMessage(text, limit) {
  if (text.length <= limit) return [text];
  const chunks = [];
  let remaining = text;
  while (remaining.length > limit) {
    let splitAt = remaining.lastIndexOf('\n\n', limit);
    if (splitAt < limit * 0.5) splitAt = remaining.lastIndexOf('\n', limit);
    if (splitAt < limit * 0.5) splitAt = remaining.lastIndexOf('. ', limit);
    if (splitAt < 0 || splitAt < limit * 0.3) splitAt = limit;
    chunks.push(remaining.slice(0, splitAt).trim());
    remaining = remaining.slice(splitAt).trim();
  }
  if (remaining) chunks.push(remaining);
  return chunks;
}

const chunks = splitMessage(text, limit);
return chunks.map((chunk, i) => ({
  json: {
    ...$input.item.json,
    chunk,
    chunk_index: i,
    total_chunks: chunks.length
  }
}));

// Build Discord message body — always plain content
const input = $input.item.json;
const body = { content: input.chunk };
return [{ json: { ...input, discord_body: JSON.stringify(body) } }];

// Build Polisher Context — assemble polisher input with soul.md and full context
// STRATEGY: replace — entire polisher context rebuilt from inputs on every message
const fs = require('fs');
// STRATEGY: replace — soul.md read from disk at runtime, updated by Reflection/ToneCraft
const soulMd = fs.readFileSync('/home/node/aerys-config/soul.md', 'utf8');
const intermediateSteps = JSON.parse($json.intermediateSteps || '[]');

// STRATEGY: skip_if_empty — only included when tools were called
// Format tool return data for polisher awareness
let toolContext = '';
if (intermediateSteps.length > 0) {
  toolContext = '## Tool Results\n' + intermediateSteps.map(step => {
    const obs = typeof step.observation === 'string'
      ? step.observation.substring(0, 2000)
      : JSON.stringify(step.observation).substring(0, 2000);
    return `[${step.action?.tool || 'unknown'}]: ${obs}`;
  }).join('\n\n');
}

// System message: identity + context (no rules)
const systemPrompt = [
  // STRATEGY: replace — soul.md personality, updated at runtime by editing file
  `## Background\n${soulMd}`,
  toolContext,
  // STRATEGY: replace — forwarded from adapter, rebuilt each message
  $json.memory_context ? `## Relevant Memories\n${$json.memory_context}` : '',
  $json.thread_context ? `## Recent Conversation\n${$json.thread_context}` : '',
  // STRATEGY: replace — forwarded from adapter, rebuilt each message
  $json.profile_context ? `## Person Profile\n${$json.profile_context}` : '',
].filter(Boolean).join('\n\n');

// Prompt: instruction + core agent output + rules
const privacyRule = $json.conversation_privacy === 'public'
  ? '- PUBLIC CHANNEL: Scrub specific PII from your output (phone numbers, addresses, SSNs, medical details). Generalize sensitive facts. Names and general preferences are fine.'
  : '- PRIVATE DM: No PII restrictions. Share all information freely.';

const polisherPrompt = `Rewrite the following Core Agent response in your voice — Aerys's voice as defined in your Background. Preserve all factual content and tool results.

## Core Agent Response
${$json.output}

## Rules
- Rewrite in YOUR voice. You are Aerys. The Core Agent response is raw material -- make it sound like you.
- PRESERVE all source URLs, citations, and links from tool results. If the Core Agent cited sources, those sources MUST appear in your rewrite. Do not drop URLs.
- If the response references tool results, incorporate them naturally but keep the factual content and sources intact.
${privacyRule}
- Never use em dashes. Use double hyphens (--), commas, or restructure the sentence instead.
- Do NOT add preambles like "Here's my rewrite." Just output the polished response directly.
- Keep the response length similar to the Core Agent's. Do not pad or over-explain.`;

return [{json: {
  ...$json,
  polisher_system_prompt: systemPrompt,
  polisher_prompt: polisherPrompt,
  intermediateSteps
}}];

// SQL write-back: update n8n_chat_histories with polished response
// so stored conversation matches what user actually saw
const polishedResponse = $json.polished_response || $json.output;
const sessionId = $json.session_id || $json.person_id;
return [{json: {
  ...$json,
  wb_polished_content: polishedResponse,
  wb_session_id: sessionId
}}];

// Hardcoded — n8n Variables are Enterprise-only on this instance
const DEBUG_ENABLED = true; // flip to false to disable traces
return [{json: {...$json, _debug_enabled: DEBUG_ENABLED}}];

// Crabwalk-style trace — NO user content, NO Aerys response text (privacy)
const steps = $json.intermediateSteps || [];
const model = ($json.model_tier || 'unknown').charAt(0).toUpperCase() + ($json.model_tier || 'unknown').slice(1);
const startTs = $json._start_ts || Date.now();
const elapsed = ((Date.now() - startTs) / 1000).toFixed(1);

const TOOL_PATTERNS = [
  { pattern: /media/i, icon: '[IMG]', label: 'media' },
  { pattern: /research/i, icon: '[RES]', label: 'research' },
  { pattern: /email/i, icon: '[EML]', label: 'email' },
];

function matchTool(toolName) {
  if (!toolName) return { icon: '[?]', label: 'unknown' };
  const match = TOOL_PATTERNS.find(p => p.pattern.test(toolName));
  return match || { icon: '[?]', label: toolName };
}

let lines = [`[${model}] ${elapsed}s`];

if (steps.length === 0) {
  lines.push('+-- Direct response');
} else {
  let totalTokens = 0;
  steps.forEach((step, i) => {
    const isLast = i === steps.length - 1;
    const prefix = isLast ? '+--' : '|--';
    const tool = matchTool(step.action?.tool);
    const tokens = step.tokenUsage?.totalTokens || 0;
    totalTokens += tokens;
    const tokenStr = tokens > 0 ? ` ${tokens} tokens` : '';
    lines.push(`${prefix} ${tool.icon} ${tool.label}${tokenStr}`);
  });
  if (totalTokens > 0) {
    lines.push(`+-- Total: ${totalTokens.toLocaleString()} tokens`);
  }
}

return [{json: {
  trace_message: '```\n' + lines.join('\n') + '\n```',
  debug_channel_id: 'YOUR_DEBUG_CHANNEL_ID'
}}];

// Bypass polisher — jailbreak deflections are already in-character
// Pass output through as polished_response unchanged
return [{json: {
  ...$json,
